def predict(triples: list[Triple]) -> str:
    """Generate a natural language sentence from a list of triples."""
    if not triples:
        return ""
    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        if p == "numberOfMembers":
            parts.append(f"{s} has {o} members")
        elif p == "season":
            parts.append(f"{s} played in the {o} season")
        elif p == "league":
            parts.append(f"{s} competes in the {o} league")
        elif p == "manager":
            parts.append(f"{s} is managed by {o}")
        elif p == "ground":
            parts.append(f"The home ground of {s} is {o}")
        elif p == "fullName":
            parts.append(f"The full name of {s} is {o}")
        elif p == "chairman":
            parts.append(f"The chairman of {s} is {o}")
        elif p == "location":
            parts.append(f"{s} is located in {o}")
        elif p == "owner":
            parts.append(f"{s} is owned by {o}")
        elif p == "nickname":
            parts.append(f"The nickname of {s} is {o}")
        elif p == "chairmanTitle":
            parts.append(f"The {o} of {s} is its chairman")
        elif p == "isPartOf":
            parts.append(f"{s} is part of {o}")
        elif p == "leader":
            parts.append(f"The leader of {s} is {o}")
        elif p == "part":
            parts.append(f"{s} includes {o}")
        elif p == "mayor":
            parts.append(f"The mayor of {s} is {o}")
        elif p == "champions":
            parts.append(f"The champions of {s} are {o}")
        elif p == "country":
            parts.append(f"{s} is in {o}")
        elif p == "club":
            parts.append(f"{s} plays for {o}")
        elif p == "capital":
            parts.append(f"The capital of {s} is {o}")
        elif p == "currency":
            parts.append(f"The currency of {s} is {o}")
        elif p == "demonym":
            parts.append(f"The demonym of {s} is {o}")
        elif p == "language":
            parts.append(f"The language of {s} is {o}")
        elif p == "leaderParty":
            parts.append(f"The leader party of {s} is {o}")
        elif p == "officialLanguage":
            parts.append(f"The official language of {s} is {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "youthclub":
            parts.append(f"{s} played for youth club {o}")
        elif p == "operator":
            parts.append(f"{s} is operated by {o}")
        elif p == "tenant":
            parts.append(f"The tenant of {s} is {o}")
        elif p == "city":
            parts.append(f"{s} is in the city of {o}")
        elif p == "state":
            parts.append(f"{s} is in the state of {o}")
        else:
            parts.append(f"{s} {p} {o}")
    # Combine parts into a single fluent sentence.
    if not parts:
        return ""
    # Capitalize the first clause (in case it was generated in lower case)
    parts[0] = parts[0][0].upper() + parts[0][1:] if parts[0] else parts[0]
    # Lower‑case the first word of subsequent clauses for smoother reading
    for i in range(1, len(parts)):
        if parts[i]:
            parts[i] = parts[i][0].lower() + parts[i][1:]
    if len(parts) == 1:
        sentence = parts[0] + "."
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1] + "."
    return sentence

